sp_widget.client_script:
api.controller = function($scope) {
	/* widget controller */
	var c = this;
	c.shared = c.widget.options.shared;

	c.onCancel = function() {
		c.shared.cancelled=true;
		$scope.$parent.$parent.buttonClicked({ label: "Cancel", cancel: true });
	};

	// when the label is clicked update the radio button
	c.labelClick = function(value){
		c.data.updateType = value;
	}
	c.onSubmit = function() {
		c.shared.updateType=c.data.updateType;
		$scope.$parent.$parent.buttonClicked({ label: "OK", primary: true });

	};

};

