// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// WIDGET BASE: Tasker Modal - Reopen Task
//------------------------------------------------------------------------------------------------------------------------
// 2.8.0 | 2022-07-07 | raj  | STRY0116785 - ICE- Confirmation Modal: Updating OU Abbreviation updates Tasker Number 
//                                          New Widget
//
//------------------------------------------------------------------------------------------------------------------------

(function($sp, input, data, options) {
	main();

	function main() {
		data.sys_id = (input || {}).sys_id || (options || {}).sys_id || $sp.getValue('sys_id');		
		// 2.8.0 | 2022-04-12 | mmcc | STRY0113587 - Mass Reopen Task Modal- Update Labels for UX; reorder and added _getDescendantsCount()
		_setDataDefaults();
		_optCopy(['sys_id']);
//		_getTaskData();
		_getTaskCounts();
		_buildMessages();
	}

	// Use this function to get Messages that will be used in this widget
	function _buildMessages() {
		data.cancelButtonText = gs.getMessage('cancel');
		data.submitButtonText = gs.getMessage('Tasker - Button - Update');
		data.submitButtonTitle = gs.getMessage('Tasker - Button - Update');

		data.msgBody2 = gs.getMessage('Warning');

		data.msgBody3 = gs.getMessage('Tasker - You are about to update the OU Abbreviation');



		data.msgBody4 = gs.getMessage('Tasker - OU Abbreviation is referenced in Tasker Number');
		data.msgBody5 = gs.getMessage('Tasker - Please choose which existing tasks to update');

		data.msgBodyActiveTasksOnly = gs.getMessage('Tasker - Only Active Tasks in the OU ({0} tasks will be updated)',[data.activeTasksInOU]);
		data.msgBodyAllTasks = gs.getMessage('Tasker - Active and Closed Tasks in the OU ({0} tasks will be updated)', [data.allTasksInOU]);
		// 2.8.0 | 2022-04-12 | mmcc | STRY0113587 - Mass Reopen Task Modal- Update Labels for UX
		// data.msgBody2TasksByDate = gs.getMessage('Tasker - This Task and all Subtasks closed on or after');
		data.msgBodyFutureOnly = gs.getMessage('Tasker - Only on New Tasks');
	}

	// Use this function to get a count of active tasks in OU
	// and the count of all tasks in the OU
	function _getTaskCounts() {
		var taskerHelpers = new TaskerHelpers();
		data.activeTasksInOU = taskerHelpers.countTasksInOU(data.sys_id, true);
		data.allTasksInOU = taskerHelpers.countTasksInOU(data.sys_id, false);
	}

	// copy to data from input or options
	function _optCopy(names) {
		names.forEach(function(name) {
			data[name] = input[name] || options[name];
		});
	}

	// Use this function to set defaults
	function _setDataDefaults() {
		// set a default radio button as selected
		data.updateType = 'activeTasksOnly';
	}
})($sp, input, data, options);
